@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
* {
  box-sizing: border-box;
  font-family: "Figtree", sans-serif;
  margin: 0;
  padding: 0;
}

.wrap {
  padding: 4px;
}

.toolbar {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 12px;
}

.search-box {
  flex: 1;
  display: flex;
  align-items: center;
  gap: 8px;
  background: rgba(5, 4, 46, 0.04);
  border: 0.5px solid rgba(0, 0, 0, 0.1);
  border-radius: 6px;
  padding: 7px 10px;
}

.search-box input {
  flex: 1;
  border: none;
  background: transparent;
  font-size: 13px;
  font-weight: 500;
  color: #05042E;
  outline: none;
  font-family: "Figtree", sans-serif;
}

.search-box input::placeholder {
  color: #888780;
}

.result-count {
  font-size: 11px;
  font-weight: 600;
  color: #888780;
  white-space: nowrap;
}

table {
  width: 100%;
  border-collapse: collapse;
}

th {
  text-align: left;
  padding: 9px 12px;
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.08);
}

td {
  padding: 11px 12px;
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.06);
  vertical-align: middle;
}

tr:last-child td {
  border-bottom: none;
}

tr:hover td {
  background: #f9f8f6;
}

.empty-row td {
  text-align: center;
  color: #888780;
  font-weight: 500;
  padding: 24px;
}

.part-cell {
  display: flex;
  align-items: center;
  gap: 6px;
}

.battery-icon {
  font-size: 12px;
}

.status-pill {
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.03em;
  padding: 3px 10px;
  border-radius: 20px;
  white-space: nowrap;
  display: inline-block;
}

.status-salvage {
  background: #E1F5EE;
  color: #085041;
}

.status-scrap {
  background: #FAEEDA;
  color: #633806;
}

.status-removed {
  background: rgba(5, 4, 46, 0.06);
  color: #888780;
}

.overdue-pill {
  font-size: 10px;
  font-weight: 700;
  padding: 3px 10px;
  border-radius: 20px;
  background: #fee2e2;
  color: #b91c1c;
}

.no-overdue {
  color: #888780;
  font-size: 12px;
}

.grade-pill {
  font-size: 10px;
  font-weight: 700;
  padding: 2px 8px;
  border-radius: 4px;
  background: rgba(5, 4, 46, 0.06);
  color: #05042E;
}

.grade-pending {
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.03em;
  padding: 3px 10px;
  border-radius: 20px;
  background: rgba(5, 4, 46, 0.06);
  color: #888780;
}

.btn-remove {
  font-family: "Figtree", sans-serif;
  font-size: 11px;
  font-weight: 700;
  padding: 5px 12px;
  border-radius: 6px;
  border: none;
  background: #A3E851;
  color: #05042E;
  cursor: pointer;
  white-space: nowrap;
}

.btn-remove:hover {
  background: #5DC987;
}

.btn-remove.scrap {
  background: #dc2626;
  color: #fff;
}

.btn-remove.scrap:hover {
  background: #b91c1c;
}

