var allRows = [];
function escHtml(str) {
  if (str === null || str === undefined) return '';
  return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}
function statusPill(status) {
  if (status === 'in_asset_salvageable') return '<span class="status-pill status-salvage">Salvageable</span>';
  if (status === 'in_asset_scrap') return '<span class="status-pill status-scrap">Scrap</span>';
  if (status === 'removed') return '<span class="status-pill status-removed">Removed</span>';
  return '—';
}
function renderRows(rows) {
  const tbody = document.getElementById('table_body');
  const count = document.getElementById('result_count');
  count.textContent = rows.length + ' part' + (rows.length !== 1 ? 's' : '');
  if (!rows.length) {
    tbody.innerHTML = '<tr class="empty-row"><td colspan="6">No parts found</td></tr>';
    return;
  }
  tbody.innerHTML = rows.map(function (r, idx) {
    const battery = r.is_battery ? '<span class="battery-icon">🔋</span>' : '';
    const canRemove = r.row_status === 'in_asset_salvageable' || r.row_status === 'in_asset_scrap';
    const isScrap = r.row_status === 'in_asset_scrap';
    const removeBtnClass = 'btn-remove' + (isScrap ? ' scrap' : '');
    const removeBtnLabel = isScrap ? 'Remove & Scrap' : 'Remove Part';
    const overdueHtml = r.is_overdue ? '<span class="overdue-pill">Overdue</span>' : '<span class="no-overdue">—</span>';
    const gradeHtml = r.condition_grade ? '<span class="grade-pill">' + escHtml(r.condition_grade) + '</span>' : r.row_status !== 'removed' ? '<span class="grade-pending">Awaiting</span>' : '—';
    const locationHtml = r.current_location_name ? escHtml(r.current_location_code + ' — ' + r.current_location_name) : r.installed_in_ref ? 'On ' + escHtml(r.installed_in_ref) : r.row_status !== 'removed' ? 'In Asset' : '—';
    return '<tr>' + '<td><div class="part-cell">' + battery + '<span>' + escHtml(r.part_type || '—') + '</span></div></td>' + '<td>' + statusPill(r.row_status) + '</td>' + '<td>' + gradeHtml + '</td>' + '<td>' + locationHtml + '</td>' + '<td>' + overdueHtml + '</td>' + '<td>' + (canRemove ? '<button class="' + removeBtnClass + '" data-idx="' + idx + '">' + removeBtnLabel + '</button>' : '') + '</td>' + '</tr>';
  }).join('');
  tbody.querySelectorAll('.btn-remove').forEach(function (btn) {
    btn.addEventListener('click', function () {
      const row = rows[Number(this.dataset.idx)];
      appsmith.updateModel({
        selectedRow: row
      });
      appsmith.triggerEvent('onRemovePart');
    });
  });
}
window.applyFilter = function () {
  const q = (document.getElementById('search_input').value || '').toLowerCase().trim();
  if (!q) {
    renderRows(allRows);
    return;
  }
  const filtered = allRows.filter(function (r) {
    return (r.part_type || '').toLowerCase().includes(q) || (r.serial_number || '').toLowerCase().includes(q) || (r.current_location_name || '').toLowerCase().includes(q);
  });
  renderRows(filtered);
};
function render(model) {
  allRows = model && Array.isArray(model.parts) ? model.parts : [];
  applyFilter();
}
function initWhenReady() {
  if (typeof appsmith === 'undefined' || !appsmith.onReady) {
    setTimeout(initWhenReady, 50);
    return;
  }
  appsmith.onReady(() => render(appsmith.model));
  appsmith.onModelChange(() => render(appsmith.model));
}
initWhenReady();

